export default {
	data() {
		return {
			InputBottom: 0,
			code: '',
			orderList: [],
			keyword: '',
			status: '',
			type: '',
			projetcText:'全部项目',
			statusText: '全部状态',
			typeText: '全部订单',
			modalName: '',
			contents: '',
			p_id:'',
			orderProject:[{p_name:'全部项目',p_id:'-1'}],
			p_index:0
		};
	},
	
	onLoad() {
		this.p_id =  this.$store.state.project_id;
		this.getOrderList();
		this.getProject();
	},
	methods: {
		changeProject(e) {
			this.p_index = e.detail.value;
			if(this.orderProject[this.p_index].p_id != -1){
				this.p_id = this.orderProject[this.p_index].p_id;
				this.getOrderList();
			}
		},
		getProject(){
			this.$api.Getprojectlistorderapi({},res =>{
				if(res.code == 1000){
					this.orderProject = [{p_name:'全部项目',p_id:'-1'}];
					res.data.forEach(res =>{
						this.orderProject.push(res)
					})
				}
			})
		},
		stop(){},
		order() {
			let _this = this;
			let items = ['全部订单', '排号订单', '认购订单'];
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.typeText = items[res.tapIndex];
					if (res.tapIndex == 0) {
						_this.type = '';
					}
					if (res.tapIndex != 0) {
						_this.type = res.tapIndex;
					}
					_this.getOrderList();
				}
			});
		},
		detail(item){
			uni.navigateTo({
				url:'/pages/order/detail?cbo_id='+item.cbo_id
			})
		},
		
		clickStatus() {
			let _this = this;
			let items = ['全部状态', '未付款', '已付款', '已失效'];
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.statusText = items[res.tapIndex];
					if (res.tapIndex == 0) {
						_this.status = '';
					}
					if (res.tapIndex == 1) {
						_this.status = 1;
					}
					if (res.tapIndex == 2) {
						_this.status = 2;
					}
					if (res.tapIndex == 3) {
						_this.status = 9;
					}
					_this.getOrderList();
				}
			});
		},
		cancel(item) {
			let _this = this;
			uni.showModal({
				title: '取消订单',
				content: '是否取消订单？',
				success(res) {
					if (res.confirm) {
						_this.$api.SalesProjectCancelorder({ order_id: item.cbo_id }, res => {
							_this.getOrderList();
						});
					}
				}
			});
		},
		getOrderList() {
			let data = {
				pid:this.p_id,	//是	int	项目id
				type:this.type,//	是	int	订单类型（1-排号，2-认购，3-排号补款，4-购房款补款）
				status:this.status,//	是	int	订单支付状态 1=未支付 2=已支付 9=已撤销/已失效
				keyword:this.keyword,//	是	string	订单号、客户名称、联系电话关键字查询
			};
			uni.showLoading({
				title:'正在获取数据...'
			})
			this.$api.indexOrderapi(data, res => {
				this.orderList = res.data.data;
			});
		},
		InputFocus(e) {
			this.InputBottom = e.detail.height;
		},
		InputBlur(e) {
			this.InputBottom = 0;
		},
		getPhoneNumber(e) {
			if (e.detail.iv) {
				this.login(e.detail.iv, e.detail.encryptedData);
			} else {
				uni.showToast({
					icon: 'none',
					title: '请继续授权，以保证能正常使用'
				});
			}
		}
	}
};
